import React from 'react';
import { StyledPage } from './styles';
import Header from '../Components/Header';
import Footer from '../Components/Footer';

interface PageProps {
    children?: React.ReactNode
}

const Page: React.FC<PageProps> = ({ children }) =>
<StyledPage>
    <Header/>
      {children}
    <Footer/>
</StyledPage>;

export default Page;
